import React, { useState, useEffect } from 'react';
import { Div, Input, Button, Spinner, Select } from '@vkontakte/vkui';
import { getStudents, linkUser } from '../api';

export default function LinkPage({ onLinked }) {
  const [students, setStudents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedName, setSelectedName] = useState('');
  const [manualName, setManualName] = useState('');

  useEffect(() => {
    getStudents().then(data => {
      setStudents(data.map(s => s.full_name).filter(Boolean));
      setLoading(false);
    });
  }, []);

  const handleSubmit = async () => {
    const finalName = selectedName || manualName;
    if (!finalName) return;
    await linkUser(finalName);
    onLinked();
  };

  if (loading) return <Spinner />;
  return (
    <Div>
      <div style={{ marginBottom: 16 }}>
        <Select
          top="Выберите своё ФИО из списка"
          placeholder="Не найдены? Введите вручную"
          options={students.map(name => ({ label: name, value: name }))}
          value={selectedName}
          onChange={(e) => setSelectedName(e.target.value)}
        />
      </div>
      <div style={{ marginBottom: 16 }}>
        <Input
          top="Или введите ФИО полностью"
          value={manualName}
          onChange={(e) => setManualName(e.target.value)}
        />
      </div>
      <Button size="l" stretched onClick={handleSubmit}>Подтвердить</Button>
    </Div>
  );
}