import React, { useEffect, useState } from 'react';
import bridge from '@vkontakte/vk-bridge';
import { AdaptivityProvider, AppRoot, View, Panel, PanelHeader, SplitLayout, SplitCol } from '@vkontakte/vkui';
import NavBar from './components/NavBar';
import SchedulePage from './components/SchedulePage';
import StudentsPage from './components/StudentsPage';
import BellPage from './components/BellPage';
import LinkPage from './components/LinkPage';
import { getMe } from './api';

function App() {
  const [activePanel, setActivePanel] = useState('schedule');
  const [isLinked, setIsLinked] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    bridge.send('VKWebAppInit');
    getMe().then(data => {
      setIsLinked(data.is_linked);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  if (loading) return <div>Загрузка...</div>;
  if (!isLinked) return <LinkPage onLinked={() => setIsLinked(true)} />;

  return (
    <AdaptivityProvider>
      <AppRoot>
        <SplitLayout>
          <SplitCol>
            <View activePanel={activePanel}>
              <Panel id="schedule">
                <PanelHeader>Расписание</PanelHeader>
                <SchedulePage />
              </Panel>
              <Panel id="students">
                <PanelHeader>Студенты</PanelHeader>
                <StudentsPage />
              </Panel>
              <Panel id="bell">
                <PanelHeader>Расписание звонков</PanelHeader>
                <BellPage />
              </Panel>
            </View>
            <NavBar activePanel={activePanel} setActivePanel={setActivePanel} />
          </SplitCol>
        </SplitLayout>
      </AppRoot>
    </AdaptivityProvider>
  );
}

export default App;