const API_BASE = 'https://vk-schedule-backend.onrender.com';

export async function callApi(endpoint, params = {}, method = 'GET') {
  const userId = 170242848; // ваш фиксированный VK ID
  
  let url = `${API_BASE}${endpoint}`;
  const options = { method, headers: { 'Content-Type': 'application/json' } };
  
  if (method === 'GET') {
    const query = new URLSearchParams({ vk_user_id: userId, ...params }).toString();
    url += `?${query}`;
  } else {
    options.body = JSON.stringify({ vk_user_id: userId, ...params });
  }
  
  console.log('Fetching:', url);
  const response = await fetch(url, options);
  if (!response.ok) throw new Error(`HTTP ${response.status}`);
  return response.json();
}

export async function getScheduleForDate(date) {
  return callApi('/api/schedule/date', { date });
}
export async function getScheduleRange(start, end) {
  return callApi('/api/schedule/range', { start, end });
}
export async function getStudents() {
  return callApi('/api/students');
}
export async function getBellSchedule() {
  return callApi('/api/bell');
}
export async function refreshData() {
  return callApi('/api/admin/refresh', {}, 'POST');
}
export async function linkUser(fullName) {
  return callApi('/api/auth/link', { full_name: fullName }, 'POST');
}
export async function getMe() {
  return callApi('/api/auth/me');
}