import React from 'react';
import { Tabbar, TabbarItem } from '@vkontakte/vkui';
import { Icon28CalendarOutline, Icon28UsersOutline, Icon28ClockOutline } from '@vkontakte/icons';  // заменено TimerOutline на ClockOutline

export default function NavBar({ activePanel, setActivePanel }) {
  return (
    <Tabbar>
      <TabbarItem onClick={() => setActivePanel('schedule')} selected={activePanel === 'schedule'}>
        <Icon28CalendarOutline />
      </TabbarItem>
      <TabbarItem onClick={() => setActivePanel('students')} selected={activePanel === 'students'}>
        <Icon28UsersOutline />
      </TabbarItem>
      <TabbarItem onClick={() => setActivePanel('bell')} selected={activePanel === 'bell'}>
        <Icon28ClockOutline />    {/* заменено */}
      </TabbarItem>
    </Tabbar>
  );
}