import React, { useEffect, useState } from 'react';
import { Group, Cell, Spinner, Div } from '@vkontakte/vkui';
import { getBellSchedule } from '../api';

export default function BellPage() {
  const [schedule, setSchedule] = useState({});
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getBellSchedule().then(data => {
      setSchedule(data);
      setLoading(false);
    });
  }, []);

  if (loading) return <Spinner />;
  return (
    <Div>
      <Group>
        {Object.entries(schedule).map(([pair, time]) => (
          <Cell key={pair} multiline>
            <b>{pair}</b> – {time}
          </Cell>
        ))}
      </Group>
    </Div>
  );
}