import React, { useState, useEffect } from 'react';
import { Calendar, Group, Cell, Button, Div, Spinner } from '@vkontakte/vkui';
import { format, addDays } from 'date-fns';
import { ru } from 'date-fns/locale';
import { getScheduleForDate, getScheduleRange } from '../api';

export default function SchedulePage() {
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [schedule, setSchedule] = useState(null);
  const [loading, setLoading] = useState(false);
  const [fullSchedule, setFullSchedule] = useState([]);
  const [showAll, setShowAll] = useState(false);

  useEffect(() => {
    if (!showAll) {
      loadScheduleForDate(selectedDate);
    }
  }, [selectedDate, showAll]);

  const loadScheduleForDate = async (date) => {
    setLoading(true);
    const data = await getScheduleForDate(format(date, 'yyyy-MM-dd'));
    setSchedule(data);
    setLoading(false);
  };

  const loadFullSchedule = async () => {
    setLoading(true);
    const start = format(new Date(), 'yyyy-MM-dd');
    const end = format(addDays(new Date(), 30), 'yyyy-MM-dd');
    const data = await getScheduleRange(start, end);
    setFullSchedule(data);
    setShowAll(true);
    setLoading(false);
  };

  if (loading) return <Spinner />;

  if (showAll) {
    return (
      <Div>
        <Button onClick={() => setShowAll(false)} mode="secondary" style={{ marginBottom: 16 }}>Назад к выбору дня</Button>
        {fullSchedule.map(day => (
          <Group key={day.date} header={<div style={{ fontWeight: 'bold' }}>{format(new Date(day.date), 'dd MMMM yyyy', { locale: ru })}</div>}>
            {day.pairs.length === 0 ? <Cell>Нет пар</Cell> : day.pairs.map((pair, idx) => (
              <Cell key={idx} multiline>
                <b>{pair[0]}</b> {pair[1]}<br />
                Ауд. {pair[2]}<br />
                {pair[3]}
              </Cell>
            ))}
          </Group>
        ))}
      </Div>
    );
  }

  return (
    <Div>
      <Calendar value={selectedDate} onChange={setSelectedDate} disablePast={false} />
      <Button onClick={loadFullSchedule} mode="primary" stretched style={{ margin: '16px 0' }}>
        Показать всё расписание
      </Button>
      {schedule && schedule.pairs && (
        <Group>
          {schedule.pairs.length === 0 && <Cell>Пар нет</Cell>}
          {schedule.pairs.map((pair, idx) => (
            <Cell key={idx} multiline>
              <b>{pair[0]}</b> {pair[1]}<br />
              Ауд. {pair[2]}<br />
              {pair[3]}
            </Cell>
          ))}
        </Group>
      )}
    </Div>
  );
}